namespace BgControls.Windows.Controls.DragDrop.NativeWrappers;/// <summary>/// 原生鼠标操作包装类，提供获取系统光标位置的功能./// </summary>internal static class NativeMouseWrapper{    /// <summary>    /// 原生方法定义类.    /// </summary>    private static class NativeMethods    {        /// <summary>        /// 获取鼠标光标的当前屏幕坐标.        /// </summary>        /// <param name="point">输出的 Win32 点结构.</param>        /// <returns>操作成功返回 true. </returns>        [DllImport("user32.dll")]        [return: MarshalAs(UnmanagedType.Bool)]        internal static extern bool GetCursorPos(out Win32Point point);    }    /// <summary>    /// 获取相对于指定视觉元素的鼠标位置.    /// </summary>    /// <param name="relativeTo">参考的视觉对象.</param>    /// <returns>转换后的坐标点. </returns>    public static Point GetPosition(Visual relativeTo)    {        // 调用原生接口获取屏幕位置.        Win32Point cursorPoint = default(Win32Point);        NativeMethods.GetCursorPos(out cursorPoint);        // 将屏幕坐标点转换为 WPF 坐标点.        Point screenPoint = new Point(cursorPoint.X, cursorPoint.Y);        // 如果参考对象不为空，则转换到该对象的坐标系，否则直接返回屏幕坐标.        return relativeTo?.PointFromScreen(screenPoint) ?? screenPoint;    }    /// <summary>    /// 获取屏幕坐标系下的光标位置.    /// </summary>    /// <param name="point">输出的 Win32 点结构.</param>    /// <returns>操作成功返回 true. </returns>    public static bool GetCursorPos(out Win32Point point)    {        // 直接调用内部原生方法.        return NativeMethods.GetCursorPos(out point);    }}